function solve(nums: number[]): number {
    const n = nums.length;
    const sorted = [...nums].sort((a, b) => a - b);

    // For each possible k, check if we can sort the array using swaps with AND equal to k
    for (let k = n - 1; k >= 0; k--) {
        // Check if we can sort the array with k
        let canSort = true;
        const visited = new Set<number>();

        for (let i = 0; i < n; i++) {
            if (visited.has(i)) continue;

            // Find a number in the array that can be swapped with nums[i] to get k
            let j = -1;
            for (let m = i + 1; m < n; m++) {
                if (!visited.has(m) && (nums[i] & nums[m]) === k) {
                    j = m;
                    break;
                }
            }

            if (j === -1) {
                canSort = false;
                break;
            }

            // Swap the elements
            [nums[i], nums[j]] = [nums[j], nums[i]];
            visited.add(i);
            visited.add(j);
        }

        // Check if the array is sorted
        if (nums.every((val, idx) => val === sorted[idx])) {
            return k;
        }
    }

    return 0;
}

