                if (visited.count(m)) continue;
                if ((temp[i] & temp[m]) == k) {
                    j = m;
                    break;
                }
            }

            if (j == -1) {
                break;
            }

            swap(temp[i], temp[j]);
            visited.insert(i);
            visited.insert(j);
        }

        bool isSorted = true;
        for (int i = 0; i < n; i++) {
            if (temp[i] != sorted[i]) {
                isSorted = false;
                break;
            }
        }

        if (isSorted) {
            return k;
        }
    }

    return 0;
}
